      if(pane){ window.SUGO_EXACT_AI_PANE = pane; window.SUGO_ACTIVE_PANE = pane; window.SUGO_ACTIVE_PANE_TS = Date.now(); }
      var input = document.getElementById('searchInput'); if(input) input.value = q;
